import { useState, useEffect } from "react";

function Request() {
  const [name, setName] = useState("");
  const [helpType, setHelpType] = useState("");
  const [details, setDetails] = useState("");
  const [search, setSearch] = useState("");

  const [requests, setRequests] = useState(() => {
    const savedRequests = localStorage.getItem("requests");
    return savedRequests ? JSON.parse(savedRequests) : [];
  });

  useEffect(() => {
    localStorage.setItem("requests", JSON.stringify(requests));
  }, [requests]);

  const filteredRequests = requests.filter((request) =>
    request.helpType.toLowerCase().includes(search.toLowerCase())
  );

  function handleSubmit(e) {
    e.preventDefault();

    const newRequest = {
      id: Date.now(),
      name,
      helpType,
      details,
    };

    setRequests([...requests, newRequest]);

    setName("");
    setHelpType("");
    setDetails("");
  }

  function deleteRequest(idToDelete) {
    const updatedRequests = requests.filter((request) => {
      return request.id !== idToDelete;
    });

    setRequests(updatedRequests);
  }

  return (
    <section className="form-container">
      <div className="page-header">
        <h1>Request Help</h1>

        <p>
          Submit a community support request and describe the type of help you
          need. Your request will be saved on this device using local storage.
        </p>
      </div>

      <form className="help-form" onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Your Name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          required
        />

        <select
          value={helpType}
          onChange={(e) => setHelpType(e.target.value)}
          required
        >
          <option value="">Choose help type</option>
          <option value="Education Help">Education Help</option>
          <option value="Home Services">Home Services</option>
          <option value="Tech Support">Tech Support</option>
          <option value="Volunteering Support">Volunteering Support</option>
          <option value="Other">Other</option>
        </select>

        <textarea
          placeholder="Describe your request"
          value={details}
          onChange={(e) => setDetails(e.target.value)}
          required
        ></textarea>

        <button type="submit">Send Request</button>
      </form>

      <div className="search-section">
        <h2>Search Requests</h2>

        <input
          className="search-input"
          type="text"
          placeholder="Search by help type..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {filteredRequests.length === 0 ? (
        <p className="empty-message">
          No requests found. Submit a request or try another search term.
        </p>
      ) : (
        <section className="cards">
          {filteredRequests.map((request) => (
            <div className="card" key={request.id}>
              <h3>{request.helpType}</h3>

              <p>
                <strong>Name:</strong> {request.name}
              </p>

              <p>{request.details}</p>

              <button
                className="delete-btn"
                onClick={() => deleteRequest(request.id)}
              >
                Delete
              </button>
            </div>
          ))}
        </section>
      )}
    </section>
  );
}

export default Request;
